# Thirty-second 160x90 H.264 baseline MP4 generated once with ffmpeg. Embedding the
# payload keeps CI independent of ffmpeg and gives the real player a valid range-
# requestable stream long enough for chrome auto-hide and remote-key regressions.
_VIDEO = base64.b64decode(
    ""
)

def _build_wav() -> bytes:
    sample_rate = 8_000
    frame_count = sample_rate * 2
    pcm = bytearray(frame_count * 2)
    for index in range(frame_count):
        sample = int(8_000 * math.sin(2 * math.pi * 440 * index / sample_rate))
        struct.pack_into("<h", pcm, index * 2, sample)
    output = io.BytesIO()
    with wave.open(output, "wb") as wav:
        wav.setnchannels(1)
        wav.setsampwidth(2)
        wav.setframerate(sample_rate)
        wav.writeframes(pcm)

    payload = bytearray(output.getvalue())
    info_chunks = []
    for code, value in {
        "INAM": "Resilient Track",
        "IART": "Maestro Artist",
        "IPRD": "Regression Album",
        "ITRK": "1",
        "ICRD": "2026",
    }.items():
        encoded = value.encode("utf-8") + b"\0"
        padded = encoded if len(encoded) % 2 == 0 else encoded + b"\0"
        info_chunks.append(code.encode("ascii") + struct.pack("<I", len(encoded)) + padded)
    info = b"INFO" + b"".join(info_chunks)
    payload.extend(b"LIST" + struct.pack("<I", len(info)) + info)
    struct.pack_into("<I", payload, 4, len(payload) - 8)
    return bytes(payload)


_AUDIO = _build_wav()

